class Solution:
    def maximumPrimeDifference(self, nums: List[int]) -> int:
        def is_prime(n):
            if n < 2:
                return False
            if n == 2:
                return True
            if n % 2 == 0:
                return False
            for i in range(3, int(n**0.5) + 1, 2):
                if n % i == 0:
                    return False
            return True

        first_prime_index = -1
        last_prime_index = -1

        for i, num in enumerate(nums):
            if is_prime(num):
                if first_prime_index == -1:
                    first_prime_index = i
                last_prime_index = i

        return last_prime_index - first_prime_index
